import{_ as a,o as r,c as o,ak as c}from"./chunks/framework.Bj6Oe1e0.js";const p=JSON.parse('{"title":"Mcu","description":"","frontmatter":{},"headers":[],"relativePath":"AUTOSAR 实践/MCAL 模块详解/Mcu.md","filePath":"AUTOSAR 实践/MCAL 模块详解/Mcu.md"}'),t={name:"AUTOSAR 实践/MCAL 模块详解/Mcu.md"};function l(i,e,n,u,s,h){return r(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="mcu" tabindex="-1">Mcu <a class="header-anchor" href="#mcu" aria-label="Permalink to “Mcu”">​</a></h1><p>Mcu 模块主要控制时钟、电源管理、RAM等的配置。</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to “General”">​</a></h2><p>这部分包含了 MCU 驱动的总体配置。</p><h3 id="default-error-detect" tabindex="-1">Default Error Detect <a class="header-anchor" href="#default-error-detect" aria-label="Permalink to “Default Error Detect”">​</a></h3><p>是否启用 Det 错误检查。 需要启用 Det 模块。</p><h3 id="version-info-api" tabindex="-1">Version Info API <a class="header-anchor" href="#version-info-api" aria-label="Permalink to “Version Info API”">​</a></h3><p>是否开放模块版本的 API。该API将在 Mcu_Cfg.h 中被定义。</p><h3 id="mcu-get-ram-state-api" tabindex="-1">Mcu Get Ram State API <a class="header-anchor" href="#mcu-get-ram-state-api" aria-label="Permalink to “Mcu Get Ram State API”">​</a></h3><p>选择是否启用 获取 RAM 状态的API。</p><h3 id="mcu-init-clock-api" tabindex="-1">Mcu Init Clock API <a class="header-anchor" href="#mcu-init-clock-api" aria-label="Permalink to “Mcu Init Clock API”">​</a></h3><p>选择是否开启使用 MCU 初始化时钟的 API。如果不开启，将无法使用该函数用于利用 MCU 初始化 Clock 模块，Clock 将通过写寄存器或者启动软件(bootloader) 负责初始化。</p><h3 id="mcu-no-pll" tabindex="-1">Mcu No PLL <a class="header-anchor" href="#mcu-no-pll" aria-label="Permalink to “Mcu No PLL”">​</a></h3><p>如果芯片不支持 PLL，需要开启该开关。</p><blockquote><p>PLL：PLL，全称为 Phase-Locked Loop（锁相环）,可以使一个振荡器的相位和输入信号保持同步。锁定后可以提供稳定、高速系统时钟源。</p></blockquote><h3 id="mcu-loops-timeout" tabindex="-1">Mcu Loops TimeOut <a class="header-anchor" href="#mcu-loops-timeout" aria-label="Permalink to “Mcu Loops TimeOut”">​</a></h3><p>Mcu 超时的滴答时刻(Ticks)数。范围是[0,42949672955]</p><h3 id="mcu-perform-reset-api" tabindex="-1">Mcu Perform Reset API <a class="header-anchor" href="#mcu-perform-reset-api" aria-label="Permalink to “Mcu Perform Reset API”">​</a></h3><p>选择是否开放软件触发复位的 API：<code>Mcu_PerformReset()</code>。</p><h3 id="mcucalloutbeforeperformreset" tabindex="-1">McuCalloutBeforePerformReset <a class="header-anchor" href="#mcucalloutbeforeperformreset" aria-label="Permalink to “McuCalloutBeforePerformReset”">​</a></h3><p>选择是否在软件触发复位之前执行回调函数。回调函数由 McuPerformResetCallout 的指针指向决定。</p><h3 id="mcuperformresetcallout" tabindex="-1">McuPerformResetCallout <a class="header-anchor" href="#mcuperformresetcallout" aria-label="Permalink to “McuPerformResetCallout”">​</a></h3><p>选择上述回调函数的指针（函数名），该指针指向的函数将在执行 <code>Mcu_PerformReset()</code>之前执行。</p><h3 id="mcu-timeout-method" tabindex="-1">Mcu Timeout Method <a class="header-anchor" href="#mcu-timeout-method" aria-label="Permalink to “Mcu Timeout Method”">​</a></h3><p>选择 Mcu 超时判断基于的时钟。</p><h2 id="mcuresetreasonconf" tabindex="-1">McuResetReasonConf <a class="header-anchor" href="#mcuresetreasonconf" aria-label="Permalink to “McuResetReasonConf”">​</a></h2><p>该栏列举了一系列复位（reset）的原因，这些原因带有各自的编号（McuResetReason）。可以被函数 Mcu_GetResetReason 检索。</p><p>这些原因是在 EcuM 中被参数 EcuMResetReason 定义的。</p><h2 id="mcuclocksettingconfig" tabindex="-1">McuClockSettingConfig <a class="header-anchor" href="#mcuclocksettingconfig" aria-label="Permalink to “McuClockSettingConfig”">​</a></h2><p>这是关于 MCU 时钟的设置。</p><p>对于每一个新的设置，通常包含数项内容，下面进行选择性诠释。</p><h3 id="mcuperipheralclockconfig" tabindex="-1">McuPeripheralClockConfig <a class="header-anchor" href="#mcuperipheralclockconfig" aria-label="Permalink to “McuPeripheralClockConfig”">​</a></h3><p>这是对于芯片内各个外设的时钟配置，即对于某个特定的外设的时钟设置。如：是否启用该外设；分频数等。</p><p>对于创建的新项目，该栏目是空的。可以点击右侧的 Add required elements 按钮，软件将通过在 Resource 中设定好的芯片，检索需要的外设时钟，自动添加配置。</p><h3 id="mcuclockreferencepoint" tabindex="-1">McuClockReferencePoint <a class="header-anchor" href="#mcuclockreferencepoint" aria-label="Permalink to “McuClockReferencePoint”">​</a></h3><p>这是 MCU 时钟参考点的设置。这里定义了 MCU 时钟树的参考基点。其定义了时钟基准频率，其他模块可以将其作为输入（就像在 Base 中选择的那样）。可以选择不同的时钟作为基准。</p>',36)])])}const d=a(t,[["render",l]]);export{p as __pageData,d as default};
